                                Method::POST,
                                &SessionRequest { answer:    "please".to_string(),
                                                    challenge: "hi".to_string(), }).await?;
            assert!(res1.headers()
                        .get(SET_COOKIE)
                        .expect("no set cookie header was set")
                        .to_str()?
                        .contains("session_id"));
            let (key, value) = ("hi".to_string(), "bye".to_string());
            let _res2 = api_request(&client,
                                    "kv_set",
                                    Method::PUT,
                                    &KVSetRequest { key: key.clone(),
