            let res3 = api_request(&client, "kv_get", Method::POST, &KVGetRequest { key }).await?
                                                                                        .text()
                                                                                        .await?;
            let kvrow = serde_json::from_str::<KVRow>(&res3).unwrap();
            assert!(kvrow.value == "bye");
            return Ok(());
        }
