    fn recursive(#args) -> Result<#return type>
    {
        _recursive_tail(#n, #args)
    }

    fn _recursive_tail(n : usize, args) -> Result<#return type>
    {
        n -= 1;
        if(n==0){ return Err("Custom Recursion Limit Reached"); }
        #body //but where any call to 'recursive' becomes a call to 
        //_recursive_tail(n, etc. )
    }
```
</CodeSnippet>

