<CodeSnippet>
```rust
    #[crabtime::expression]
    fn eval_as(pattern!($l:literal): _)
    {
        let mut input = stringify!($l);
        //strip leading and trailing quotes 
        assert!(input.len()>2, "input too short");
        input = &input[1..input.len()-1];
        //expecting input like eval_as!(f32, x+y+33/2.0);
        let ops = ["%","*","+","-","/"];
        let parts : Vec<&str> = input.split(",").collect();
        assert_eq!(parts.len(), 2, "Input should be 'type,expr'");
        let ty = parts[0];
        let mut mout = parts[1].to_string();
        ops.iter().for_each(|op| mout = mout.replace(op, &format!(" as {} {} ", ty, op))); 
        crabtime::output!{ {{mout}} as {{ty}} }
    }

    //in main
    let q = eval_as!("f32, 43 + 54.0f64/32f32 - 8u8 + 5");
    println!("{}",q);

    //output
    41.6875
```
